from manim import *
import numpy as np

class TunnelingPhenomena(Scene):
    def construct(self):
        title = Text("Quantum Tunneling: Exponential Decay Inside the Barrier", font_size=28).to_edge(UP)
        self.play(Write(title))

        axes = Axes(x_range=[-5, 5, 1], y_range=[0, 2.5, 1], x_length=10, y_length=5).shift(DOWN * 0.4)
        self.play(Create(axes))

        def V(x):
            return 2 if -1 <= x <= 1 else 0

        barrier = axes.plot(V, x_range=[-5, 5], use_smoothing=False, color=RED)
        self.play(Create(barrier))

        def psi(x):
            if x < -1:
                return 0.8 * np.cos(4 * (x + 5))
            elif -1 <= x <= 1:
                return 0.8 * np.cos(4 * 4) * np.exp(-2 * (x + 1))
            else:
                amp = 0.8 * np.cos(4 * 4) * np.exp(-2 * 2)
                return amp * np.cos(4 * (x - 1))

        wave = axes.plot(psi, x_range=[-5, 5], color=BLUE)
        self.play(Create(wave), run_time=3)

        region_label = Text("Exponential decay: ψ ~ e^(-κx)", font_size=22, color=YELLOW).next_to(axes, DOWN)
        self.play(Write(region_label))
        self.wait(2)

```

