from manim import *
import numpy as np

class IsotopeEffectsTunneling(Scene):
    def construct(self):
        title = Text("Isotope Effects on Tunneling: Lighter Mass Tunnels Faster", font_size=25).to_edge(UP)
        self.play(Write(title))

        axes = Axes(x_range=[-4, 4, 1], y_range=[0, 2.5, 1], x_length=9, y_length=4.5).shift(DOWN * 0.3)
        self.play(Create(axes))

        barrier = axes.plot(lambda x: 2 if -1 <= x <= 1 else 0, x_range=[-4, 4], use_smoothing=False, color=RED)
        self.play(Create(barrier))

        def wave(x, kappa):
            if x < -1:
                return 0.6 * np.cos(3 * (x + 4))
            elif -1 <= x <= 1:
                return 0.6 * np.cos(3 * 3) * np.exp(-kappa * (x + 1))
            else:
                amp = 0.6 * np.cos(3 * 3) * np.exp(-kappa * 2)
                return amp * np.cos(3 * (x - 1))

        h_wave = axes.plot(lambda x: wave(x, 1.0), x_range=[-4, 4], color=BLUE)
        d_wave = axes.plot(lambda x: wave(x, 2.2), x_range=[-4, 4], color=ORANGE)

        h_label = Text("H (light)", font_size=20, color=BLUE).to_corner(UR).shift(DOWN * 0.5)
        d_label = Text("D (heavy)", font_size=20, color=ORANGE).next_to(h_label, DOWN)

        self.play(Create(h_wave), Write(h_label))
        self.play(Create(d_wave), Write(d_label))

        note = Text("Heavier isotope: larger κ = √(2mV)/ℏ, faster decay, less tunneling", font_size=18).to_edge(DOWN)
        self.play(Write(note))
        self.wait(2)

